/**
 * API Route for lead submission
 * Handles form submission, Turnstile verification, file upload, and lead storage
 */

import { NextRequest, NextResponse } from 'next/server';
import { writeFile, mkdir } from 'fs/promises';
import { existsSync } from 'fs';
import path from 'path';

interface TurnstileResponse {
  success: boolean;
  'error-codes'?: string[];
  challenge_ts?: string;
  hostname?: string;
}

/**
 * Verify Cloudflare Turnstile token
 */
async function verifyTurnstile(token: string): Promise<boolean> {
  const secretKey = process.env.TURNSTILE_SECRET;

  if (!secretKey) {
    console.error('TURNSTILE_SECRET not configured');
    return false;
  }

  try {
    const response = await fetch('https://challenges.cloudflare.com/turnstile/v0/siteverify', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        secret: secretKey,
        response: token,
      }),
    });

    const data: TurnstileResponse = await response.json();
    return data.success;
  } catch (error) {
    console.error('Turnstile verification error:', error);
    return false;
  }
}

/**
 * Save uploaded file to storage
 */
async function saveUploadedFile(file: File): Promise<string> {
  const bytes = await file.arrayBuffer();
  const buffer = Buffer.from(bytes);

  // Create storage directory if it doesn't exist
  const storageDir = path.join(process.cwd(), 'storage', 'proofs');
  if (!existsSync(storageDir)) {
    await mkdir(storageDir, { recursive: true });
  }

  // Generate unique filename
  const timestamp = Date.now();
  const ext = path.extname(file.name);
  const filename = `proof_${timestamp}${ext}`;
  const filepath = path.join(storageDir, filename);

  // Write file
  await writeFile(filepath, buffer);

  return filename;
}

/**
 * Store lead data
 */
async function storeLead(leadData: any): Promise<void> {
  const storageDir = path.join(process.cwd(), 'storage', 'leads');
  if (!existsSync(storageDir)) {
    await mkdir(storageDir, { recursive: true });
  }

  const timestamp = Date.now();
  const filename = `lead_${timestamp}.json`;
  const filepath = path.join(storageDir, filename);

  await writeFile(filepath, JSON.stringify(leadData, null, 2));

  // Also append to CSV for easy admin review
  const csvPath = path.join(storageDir, 'leads.csv');
  const csvLine = `${leadData.timestamp},${leadData.email},${leadData.username},${leadData.productName},${leadData.sku},${leadData.price},${leadData.paymentMethod},${leadData.proofFilename}\n`;

  try {
    if (!existsSync(csvPath)) {
      // Create CSV with headers
      await writeFile(
        csvPath,
        'Timestamp,Email,Username,Product,SKU,Price,Payment Method,Proof File\n' + csvLine
      );
    } else {
      // Append to existing CSV
      const { appendFile } = await import('fs/promises');
      await appendFile(csvPath, csvLine);
    }
  } catch (error) {
    console.error('Error writing to CSV:', error);
  }
}

/**
 * Send email notification (pseudocode - requires SendGrid setup)
 */
async function sendEmailNotification(leadData: any): Promise<void> {
  // TODO: Implement SendGrid email sending
  // const sgMail = require('@sendgrid/mail');
  // sgMail.setApiKey(process.env.SENDGRID_API_KEY);

  // const msg = {
  //   to: 'admin@sa-chaos.my.id',
  //   from: 'noreply@sa-chaos.my.id',
  //   subject: `New Order: ${leadData.productName} from ${leadData.username}`,
  //   html: `
  //     <h2>New Order Received</h2>
  //     <p><strong>Product:</strong> ${leadData.productName} (${leadData.sku})</p>
  //     <p><strong>Customer:</strong> ${leadData.username} (${leadData.email})</p>
  //     <p><strong>Price:</strong> Rp ${leadData.price.toLocaleString('id-ID')}</p>
  //     <p><strong>Payment Method:</strong> ${leadData.paymentMethod}</p>
  //     <p><strong>Proof:</strong> ${leadData.proofFilename}</p>
  //     <p><strong>Time:</strong> ${new Date(leadData.timestamp).toLocaleString('id-ID')}</p>
  //   `,
  // };

  // await sgMail.send(msg);

  console.log('Email notification would be sent here:', leadData.email);
}

export async function POST(request: NextRequest) {
  try {
    // Parse form data
    const formData = await request.formData();

    const email = formData.get('email') as string;
    const username = formData.get('username') as string;
    const productId = formData.get('productId') as string;
    const productName = formData.get('productName') as string;
    const sku = formData.get('sku') as string;
    const price = parseInt(formData.get('price') as string);
    const paymentMethod = formData.get('paymentMethod') as string;
    const proofFile = formData.get('proofOfPayment') as File;
    const turnstileToken = formData.get('turnstileToken') as string;

    // Validate required fields
    if (!email || !username || !productId || !proofFile || !turnstileToken) {
      return NextResponse.json(
        { success: false, error: 'Missing required fields' },
        { status: 400 }
      );
    }

    // Verify Turnstile token
    const isTurnstileValid = await verifyTurnstile(turnstileToken);
    if (!isTurnstileValid) {
      return NextResponse.json(
        { success: false, error: 'Turnstile verification failed' },
        { status: 403 }
      );
    }

    // Validate file type
    if (!proofFile.type.startsWith('image/')) {
      return NextResponse.json(
        { success: false, error: 'Invalid file type. Only images are allowed' },
        { status: 400 }
      );
    }

    // Validate file size (5MB)
    if (proofFile.size > 5 * 1024 * 1024) {
      return NextResponse.json(
        { success: false, error: 'File size too large. Maximum 5MB' },
        { status: 400 }
      );
    }

    // Save uploaded file
    const proofFilename = await saveUploadedFile(proofFile);

    // Prepare lead data
    const leadData = {
      timestamp: new Date().toISOString(),
      email,
      username,
      productId,
      productName,
      sku,
      price,
      paymentMethod,
      proofFilename,
      ip: request.headers.get('x-forwarded-for') || request.headers.get('x-real-ip') || 'unknown',
      userAgent: request.headers.get('user-agent') || 'unknown',
    };

    // Store lead
    await storeLead(leadData);

    // Send email notification
    await sendEmailNotification(leadData);

    return NextResponse.json({
      success: true,
      message: 'Order submitted successfully',
      leadId: `lead_${Date.now()}`,
    });

  } catch (error: any) {
    console.error('Error processing lead:', error);
    return NextResponse.json(
      { success: false, error: 'Internal server error' },
      { status: 500 }
    );
  }
}

