+  return {
+    accessToken: data.access_token,
+    refreshToken: data.refresh_token,
+    expiresAt,
+    scopes: (data.scope || SCOPES).split(" "),
+  };
+}
+
+// --- Credential Storage (macOS Keychain) ---
+
+function storeCredentials(tokens: OAuthResult, logErr: (msg: string) => void): void {
