import { Request, Response } from 'express';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { coreDb, getTenantClientBySlug } from '@electioncaffe/database';
import {
  loginSchema,
  registerSchema,
  changePasswordSchema,
  successResponse,
  errorResponse,
  generateOTP,
} from '@electioncaffe/shared';
import type { UserPayload, LoginResponse } from '@electioncaffe/shared';

const JWT_SECRET = process.env.JWT_SECRET || 'your-super-secret-jwt-key-change-in-production';
const JWT_REFRESH_SECRET = process.env.JWT_REFRESH_SECRET || 'your-refresh-secret-key-change-in-production';
const ACCESS_TOKEN_EXPIRY = '15m';
const REFRESH_TOKEN_EXPIRY = '7d';

export class AuthController {
  async login(req: Request, res: Response): Promise<void> {
    try {
      console.log('🔐 [AUTH] Login attempt received:', { body: req.body });

      const validation = loginSchema.safeParse(req.body);
      if (!validation.success) {
        console.log('❌ [AUTH] Validation failed:', validation.error.errors);
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      const { mobile, email, password, tenantSlug } = validation.data;
      console.log('✅ [AUTH] Validation passed:', { mobile, email, tenantSlug });

      // Step 1: Find tenant in core database
      console.log('🔧 [AUTH] Environment check:', {
        CORE_DATABASE_URL: process.env.CORE_DATABASE_URL ? 'SET' : 'NOT SET',
        DATABASE_URL: process.env.DATABASE_URL ? 'SET' : 'NOT SET',
      });

      let tenant;
      if (tenantSlug) {
        console.log(`🔍 [AUTH] Looking up tenant by slug: "${tenantSlug}"`);
        try {
          tenant = await coreDb.tenant.findUnique({ where: { slug: tenantSlug } });
        } catch (dbError) {
          console.error('💥 [AUTH] Database error during tenant lookup:', dbError);
          throw dbError;
        }
      } else {
        console.log('🔍 [AUTH] No tenant slug provided, getting first active tenant');
        // Get first active tenant as default
        tenant = await coreDb.tenant.findFirst({ where: { status: 'ACTIVE' } });
      }

      console.log('📋 [AUTH] Tenant lookup result:', tenant ? { id: tenant.id, slug: tenant.slug, name: tenant.name, status: tenant.status } : 'null');

      if (!tenant) {
        console.log('❌ [AUTH] Tenant not found - returning 404');
        res.status(404).json(errorResponse('E3001', 'Tenant not found'));
        return;
      }

      // Check if tenant database is ready
      if (tenant.databaseStatus !== 'READY') {
        res.status(503).json(errorResponse('E5003', 'Tenant database not available'));
        return;
      }

      // Step 2: Connect to tenant database
      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      // Step 3: Find user in tenant database
      const whereClause: any = {};
      if (mobile) {
        whereClause.mobile = mobile;
      } else if (email) {
        whereClause.email = email;
      }
      whereClause.tenantId = tenant.id;

      const user = await tenantDb.user.findFirst({
        where: whereClause,
      });

      if (!user) {
        res.status(401).json(errorResponse('E1002', 'Invalid credentials'));
        return;
      }

      if (user.status !== 'ACTIVE') {
        res.status(403).json(errorResponse('E1005', 'Account is not active'));
        return;
      }

      const isPasswordValid = await bcrypt.compare(password, user.passwordHash);
      if (!isPasswordValid) {
        res.status(401).json(errorResponse('E1002', 'Invalid credentials'));
        return;
      }

      // Generate tokens
      const userPayload: UserPayload = {
        id: user.id,
        tenantId: user.tenantId,
        email: user.email || undefined,
        mobile: user.mobile,
        role: user.role as UserPayload['role'],
        permissions: user.permissions as string[] || [],
      };

      const accessToken = jwt.sign(userPayload, JWT_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRY });
      const refreshToken = jwt.sign({ id: user.id, tenantId: tenant.id }, JWT_REFRESH_SECRET, { expiresIn: REFRESH_TOKEN_EXPIRY });

      // Save refresh token in tenant database
      await tenantDb.refreshToken.create({
        data: {
          userId: user.id,
          token: refreshToken,
          expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
        },
      });

      // Update last login
      await tenantDb.user.update({
        where: { id: user.id },
        data: { lastLoginAt: new Date() },
      });

      const response: LoginResponse = {
        accessToken,
        refreshToken,
        user: userPayload,
        expiresIn: 15 * 60, // 15 minutes in seconds
      };

      res.json(successResponse(response));
    } catch (error) {
      console.error('Login error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async register(req: Request, res: Response): Promise<void> {
    try {
      const validation = registerSchema.safeParse(req.body);
      if (!validation.success) {
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      const { firstName, lastName, mobile, email, password, tenantSlug } = validation.data;

      // Find tenant in core database
      let tenant;
      if (tenantSlug) {
        tenant = await coreDb.tenant.findUnique({ where: { slug: tenantSlug } });
      } else {
        tenant = await coreDb.tenant.findFirst({ where: { status: 'ACTIVE' } });
      }

      if (!tenant) {
        res.status(404).json(errorResponse('E3001', 'Tenant not found'));
        return;
      }

      if (tenant.databaseStatus !== 'READY') {
        res.status(503).json(errorResponse('E5003', 'Tenant database not available'));
        return;
      }

      // Connect to tenant database
      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      // Check if user already exists
      const existingUser = await tenantDb.user.findFirst({
        where: { tenantId: tenant.id, mobile },
      });

      if (existingUser) {
        res.status(409).json(errorResponse('E3002', 'User with this mobile already exists'));
        return;
      }

      // Hash password
      const passwordHash = await bcrypt.hash(password, 10);

      // Create user in tenant database
      const user = await tenantDb.user.create({
        data: {
          tenantId: tenant.id,
          firstName,
          lastName,
          mobile,
          email,
          passwordHash,
          role: 'VOLUNTEER',
          status: 'ACTIVE',
        },
      });

      res.status(201).json(successResponse({
        id: user.id,
        firstName: user.firstName,
        lastName: user.lastName,
        mobile: user.mobile,
        email: user.email,
        role: user.role,
      }));
    } catch (error) {
      console.error('Register error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async refreshToken(req: Request, res: Response): Promise<void> {
    try {
      const { refreshToken } = req.body;

      if (!refreshToken) {
        res.status(400).json(errorResponse('E2003', 'Refresh token is required'));
        return;
      }

      // Verify refresh token
      const decoded = jwt.verify(refreshToken, JWT_REFRESH_SECRET) as { id: string; tenantId: string };

      // Get tenant from core database
      const tenant = await coreDb.tenant.findUnique({ where: { id: decoded.tenantId } });
      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.status(401).json(errorResponse('E1004', 'Invalid refresh token'));
        return;
      }

      // Connect to tenant database
      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      // Check if token exists in tenant database
      const storedToken = await tenantDb.refreshToken.findFirst({
        where: {
          userId: decoded.id,
          token: refreshToken,
          expiresAt: { gt: new Date() },
        },
      });

      if (!storedToken) {
        res.status(401).json(errorResponse('E1004', 'Invalid refresh token'));
        return;
      }

      // Get user from tenant database
      const user = await tenantDb.user.findUnique({
        where: { id: decoded.id },
      });

      if (!user || user.status !== 'ACTIVE') {
        res.status(401).json(errorResponse('E1004', 'User not found or inactive'));
        return;
      }

      // Generate new access token
      const userPayload: UserPayload = {
        id: user.id,
        tenantId: user.tenantId,
        email: user.email || undefined,
        mobile: user.mobile,
        role: user.role as UserPayload['role'],
        permissions: user.permissions as string[] || [],
      };

      const accessToken = jwt.sign(userPayload, JWT_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRY });

      res.json(successResponse({
        accessToken,
        expiresIn: 15 * 60,
      }));
    } catch (error) {
      if (error instanceof jwt.TokenExpiredError) {
        res.status(401).json(errorResponse('E1003', 'Refresh token expired'));
        return;
      }
      console.error('Refresh token error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async logout(req: Request, res: Response): Promise<void> {
    try {
      const userId = req.headers['x-user-id'] as string;
      const tenantId = req.headers['x-tenant-id'] as string;
      const { refreshToken } = req.body;

      if (!tenantId) {
        res.status(400).json(errorResponse('E2003', 'Tenant ID is required'));
        return;
      }

      // Get tenant and connect to tenant database
      const tenant = await coreDb.tenant.findUnique({ where: { id: tenantId } });
      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.json(successResponse({ message: 'Logged out successfully' }));
        return;
      }

      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      if (refreshToken) {
        await tenantDb.refreshToken.deleteMany({
          where: { userId, token: refreshToken },
        });
      } else {
        // Delete all refresh tokens for user
        await tenantDb.refreshToken.deleteMany({
          where: { userId },
        });
      }

      res.json(successResponse({ message: 'Logged out successfully' }));
    } catch (error) {
      console.error('Logout error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async getProfile(req: Request, res: Response): Promise<void> {
    try {
      const userId = req.headers['x-user-id'] as string;
      const tenantId = req.headers['x-tenant-id'] as string;

      if (!tenantId) {
        res.status(400).json(errorResponse('E2003', 'Tenant ID is required'));
        return;
      }

      // Get tenant from core database
      const tenant = await coreDb.tenant.findUnique({ where: { id: tenantId } });
      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.status(404).json(errorResponse('E3001', 'Tenant not found'));
        return;
      }

      // Connect to tenant database
      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      const user = await tenantDb.user.findUnique({
        where: { id: userId },
      });

      if (!user) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      res.json(successResponse({
        id: user.id,
        firstName: user.firstName,
        lastName: user.lastName,
        email: user.email,
        mobile: user.mobile,
        profilePhotoUrl: user.profilePhotoUrl,
        role: user.role,
        status: user.status,
        lastLoginAt: user.lastLoginAt,
        tenant: {
          id: tenant.id,
          name: tenant.name,
          slug: tenant.slug,
          logoUrl: tenant.logoUrl,
        },
      }));
    } catch (error) {
      console.error('Get profile error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async updateProfile(req: Request, res: Response): Promise<void> {
    try {
      const userId = req.headers['x-user-id'] as string;
      const tenantId = req.headers['x-tenant-id'] as string;
      const { firstName, lastName, email, profilePhotoUrl } = req.body;

      if (!tenantId) {
        res.status(400).json(errorResponse('E2003', 'Tenant ID is required'));
        return;
      }

      const tenant = await coreDb.tenant.findUnique({ where: { id: tenantId } });
      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.status(404).json(errorResponse('E3001', 'Tenant not found'));
        return;
      }

      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      const user = await tenantDb.user.update({
        where: { id: userId },
        data: {
          ...(firstName && { firstName }),
          ...(lastName && { lastName }),
          ...(email && { email }),
          ...(profilePhotoUrl && { profilePhotoUrl }),
        },
      });

      res.json(successResponse({
        id: user.id,
        firstName: user.firstName,
        lastName: user.lastName,
        email: user.email,
        mobile: user.mobile,
        profilePhotoUrl: user.profilePhotoUrl,
      }));
    } catch (error) {
      console.error('Update profile error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async changePassword(req: Request, res: Response): Promise<void> {
    try {
      const userId = req.headers['x-user-id'] as string;
      const tenantId = req.headers['x-tenant-id'] as string;

      const validation = changePasswordSchema.safeParse(req.body);
      if (!validation.success) {
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      if (!tenantId) {
        res.status(400).json(errorResponse('E2003', 'Tenant ID is required'));
        return;
      }

      const tenant = await coreDb.tenant.findUnique({ where: { id: tenantId } });
      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.status(404).json(errorResponse('E3001', 'Tenant not found'));
        return;
      }

      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      const { currentPassword, newPassword } = validation.data;

      const user = await tenantDb.user.findUnique({ where: { id: userId } });
      if (!user) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      const isPasswordValid = await bcrypt.compare(currentPassword, user.passwordHash);
      if (!isPasswordValid) {
        res.status(401).json(errorResponse('E1002', 'Current password is incorrect'));
        return;
      }

      const passwordHash = await bcrypt.hash(newPassword, 10);
      await tenantDb.user.update({
        where: { id: userId },
        data: { passwordHash },
      });

      // Invalidate all refresh tokens
      await tenantDb.refreshToken.deleteMany({ where: { userId } });

      res.json(successResponse({ message: 'Password changed successfully' }));
    } catch (error) {
      console.error('Change password error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async forgotPassword(req: Request, res: Response): Promise<void> {
    try {
      const { mobile, tenantSlug } = req.body;

      if (!mobile) {
        res.status(400).json(errorResponse('E2003', 'Mobile number is required'));
        return;
      }

      // Find tenant
      let tenant;
      if (tenantSlug) {
        tenant = await coreDb.tenant.findUnique({ where: { slug: tenantSlug } });
      } else {
        tenant = await coreDb.tenant.findFirst({ where: { status: 'ACTIVE' } });
      }

      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.json(successResponse({ message: 'If the mobile number exists, an OTP has been sent' }));
        return;
      }

      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      const user = await tenantDb.user.findFirst({ where: { mobile, tenantId: tenant.id } });

      if (!user) {
        // Don't reveal if user exists
        res.json(successResponse({ message: 'If the mobile number exists, an OTP has been sent' }));
        return;
      }

      // Generate OTP
      const otp = generateOTP(6);

      // Store OTP
      await tenantDb.oTP.create({
        data: {
          userId: user.id,
          code: otp,
          type: 'password_reset',
          expiresAt: new Date(Date.now() + 10 * 60 * 1000), // 10 minutes
        },
      });

      // In production, send OTP via SMS
      console.log(`OTP for ${mobile}: ${otp}`);

      res.json(successResponse({
        message: 'OTP has been sent to your mobile number',
        // Only for development
        ...(process.env.NODE_ENV === 'development' && { otp }),
      }));
    } catch (error) {
      console.error('Forgot password error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async verifyOTP(req: Request, res: Response): Promise<void> {
    try {
      const { mobile, otp, tenantSlug } = req.body;

      if (!mobile || !otp) {
        res.status(400).json(errorResponse('E2003', 'Mobile and OTP are required'));
        return;
      }

      // Find tenant
      let tenant;
      if (tenantSlug) {
        tenant = await coreDb.tenant.findUnique({ where: { slug: tenantSlug } });
      } else {
        tenant = await coreDb.tenant.findFirst({ where: { status: 'ACTIVE' } });
      }

      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.status(400).json(errorResponse('E1007', 'Invalid OTP'));
        return;
      }

      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      const user = await tenantDb.user.findFirst({ where: { mobile, tenantId: tenant.id } });

      if (!user) {
        res.status(400).json(errorResponse('E1007', 'Invalid OTP'));
        return;
      }

      const validOTP = await tenantDb.oTP.findFirst({
        where: {
          userId: user.id,
          code: otp,
          type: 'password_reset',
          expiresAt: { gt: new Date() },
          usedAt: null,
        },
      });

      if (!validOTP) {
        res.status(400).json(errorResponse('E1007', 'Invalid or expired OTP'));
        return;
      }

      // Generate a temporary token for password reset
      const resetToken = jwt.sign(
        { userId: user.id, otpId: validOTP.id, tenantId: tenant.id },
        JWT_SECRET,
        { expiresIn: '5m' }
      );

      res.json(successResponse({
        message: 'OTP verified successfully',
        resetToken,
      }));
    } catch (error) {
      console.error('Verify OTP error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async resetPassword(req: Request, res: Response): Promise<void> {
    try {
      const { resetToken, newPassword } = req.body;

      if (!resetToken || !newPassword) {
        res.status(400).json(errorResponse('E2003', 'Reset token and new password are required'));
        return;
      }

      // Verify reset token
      const decoded = jwt.verify(resetToken, JWT_SECRET) as { userId: string; otpId: string; tenantId: string };

      // Get tenant
      const tenant = await coreDb.tenant.findUnique({ where: { id: decoded.tenantId } });
      if (!tenant || tenant.databaseStatus !== 'READY') {
        res.status(400).json(errorResponse('E1006', 'Invalid reset token'));
        return;
      }

      const tenantDb = await getTenantClientBySlug(
        tenant.slug,
        {
          databaseHost: tenant.databaseHost,
          databaseName: tenant.databaseName,
          databaseUser: tenant.databaseUser,
          databasePassword: tenant.databasePassword,
          databasePort: tenant.databasePort,
          databaseSSL: tenant.databaseSSL,
          databaseConnectionUrl: tenant.databaseConnectionUrl,
        },
        tenant.id
      );

      // Mark OTP as used
      await tenantDb.oTP.update({
        where: { id: decoded.otpId },
        data: { usedAt: new Date() },
      });

      // Update password
      const passwordHash = await bcrypt.hash(newPassword, 10);
      await tenantDb.user.update({
        where: { id: decoded.userId },
        data: { passwordHash },
      });

      // Invalidate all refresh tokens
      await tenantDb.refreshToken.deleteMany({ where: { userId: decoded.userId } });

      res.json(successResponse({ message: 'Password reset successfully' }));
    } catch (error) {
      if (error instanceof jwt.TokenExpiredError) {
        res.status(400).json(errorResponse('E1006', 'Reset token expired'));
        return;
      }
      console.error('Reset password error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }
}

import { Request, Response } from 'express';
import bcrypt from 'bcryptjs';
import crypto from 'crypto';
import { prisma } from '@electioncaffe/database';
import { successResponse, errorResponse, generateOTP } from '@electioncaffe/shared';

const INVITATION_EXPIRY_DAYS = 7;

export class InvitationController {
  // Create invitation (for Tenant Admin inviting users)
  async createInvitation(req: Request, res: Response): Promise<void> {
    try {
      const userId = req.headers['x-user-id'] as string;
      const tenantId = req.headers['x-tenant-id'] as string;

      const {
        mobile,
        email,
        firstName,
        lastName,
        role,
        electionId,
        message
      } = req.body;

      if (!mobile || !firstName || !role) {
        res.status(400).json(errorResponse('E2001', 'Mobile, first name, and role are required'));
        return;
      }

      // Get inviter info
      const inviter = await prisma.user.findUnique({
        where: { id: userId },
        select: { firstName: true, lastName: true, role: true }
      });

      if (!inviter) {
        res.status(404).json(errorResponse('E3001', 'Inviter not found'));
        return;
      }

      // Check if user already exists in this tenant
      const existingUser = await prisma.user.findFirst({
        where: { tenantId, mobile }
      });

      if (existingUser) {
        res.status(409).json(errorResponse('E3002', 'User with this mobile already exists in this tenant'));
        return;
      }

      // Check for existing pending invitation
      const existingInvitation = await prisma.invitation.findFirst({
        where: {
          invitedByTenantId: tenantId,
          mobile,
          status: 'PENDING'
        }
      });

      if (existingInvitation) {
        res.status(409).json(errorResponse('E3002', 'A pending invitation already exists for this mobile'));
        return;
      }

      // Generate unique token
      const token = crypto.randomBytes(32).toString('hex');

      // Create invitation
      const invitation = await prisma.invitation.create({
        data: {
          invitationType: 'TENANT_USER',
          invitedByTenantId: tenantId,
          electionId,
          mobile,
          email,
          firstName,
          lastName,
          role,
          token,
          status: 'PENDING',
          message,
          invitedBy: userId,
          invitedByName: `${inviter.firstName} ${inviter.lastName || ''}`.trim(),
          invitedByType: 'user',
          expiresAt: new Date(Date.now() + INVITATION_EXPIRY_DAYS * 24 * 60 * 60 * 1000),
        }
      });

      // TODO: Send SMS/Email notification
      console.log(`Invitation created for ${mobile} with token: ${token}`);

      res.status(201).json(successResponse({
        id: invitation.id,
        mobile: invitation.mobile,
        email: invitation.email,
        firstName: invitation.firstName,
        lastName: invitation.lastName,
        role: invitation.role,
        status: invitation.status,
        expiresAt: invitation.expiresAt,
        inviteLink: `${process.env.APP_URL || 'http://localhost:5173'}/accept-invitation?token=${token}`,
      }));
    } catch (error) {
      console.error('Create invitation error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // Get all invitations for tenant
  async getInvitations(req: Request, res: Response): Promise<void> {
    try {
      const tenantId = req.headers['x-tenant-id'] as string;
      const { status, page = 1, limit = 20 } = req.query;

      const where: any = { invitedByTenantId: tenantId };
      if (status) {
        where.status = status;
      }

      const [invitations, total] = await Promise.all([
        prisma.invitation.findMany({
          where,
          orderBy: { createdAt: 'desc' },
          skip: (Number(page) - 1) * Number(limit),
          take: Number(limit),
          select: {
            id: true,
            mobile: true,
            email: true,
            firstName: true,
            lastName: true,
            role: true,
            status: true,
            invitedByName: true,
            expiresAt: true,
            acceptedAt: true,
            resentCount: true,
            createdAt: true,
          }
        }),
        prisma.invitation.count({ where })
      ]);

      res.json(successResponse({
        invitations,
        pagination: {
          page: Number(page),
          limit: Number(limit),
          total,
          totalPages: Math.ceil(total / Number(limit))
        }
      }));
    } catch (error) {
      console.error('Get invitations error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // Get invitation by ID
  async getInvitationById(req: Request, res: Response): Promise<void> {
    try {
      const tenantId = req.headers['x-tenant-id'] as string;
      const { id } = req.params;

      const invitation = await prisma.invitation.findFirst({
        where: { id, invitedByTenantId: tenantId }
      });

      if (!invitation) {
        res.status(404).json(errorResponse('E3001', 'Invitation not found'));
        return;
      }

      res.json(successResponse(invitation));
    } catch (error) {
      console.error('Get invitation error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // Resend invitation
  async resendInvitation(req: Request, res: Response): Promise<void> {
    try {
      const tenantId = req.headers['x-tenant-id'] as string;
      const { id } = req.params;

      const invitation = await prisma.invitation.findFirst({
        where: { id, invitedByTenantId: tenantId }
      });

      if (!invitation) {
        res.status(404).json(errorResponse('E3001', 'Invitation not found'));
        return;
      }

      if (invitation.status !== 'PENDING') {
        res.status(400).json(errorResponse('E2004', 'Can only resend pending invitations'));
        return;
      }

      // Generate new token and extend expiry
      const token = crypto.randomBytes(32).toString('hex');

      const updated = await prisma.invitation.update({
        where: { id },
        data: {
          token,
          status: 'RESENT',
          expiresAt: new Date(Date.now() + INVITATION_EXPIRY_DAYS * 24 * 60 * 60 * 1000),
          lastResentAt: new Date(),
          resentCount: invitation.resentCount + 1,
        }
      });

      // Reset status back to PENDING after recording resent
      await prisma.invitation.update({
        where: { id },
        data: { status: 'PENDING' }
      });

      // TODO: Send SMS/Email notification
      console.log(`Invitation resent to ${invitation.mobile} with new token: ${token}`);

      res.json(successResponse({
        message: 'Invitation resent successfully',
        expiresAt: updated.expiresAt,
        resentCount: updated.resentCount,
      }));
    } catch (error) {
      console.error('Resend invitation error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // Cancel invitation
  async cancelInvitation(req: Request, res: Response): Promise<void> {
    try {
      const tenantId = req.headers['x-tenant-id'] as string;
      const { id } = req.params;

      const invitation = await prisma.invitation.findFirst({
        where: { id, invitedByTenantId: tenantId }
      });

      if (!invitation) {
        res.status(404).json(errorResponse('E3001', 'Invitation not found'));
        return;
      }

      if (invitation.status === 'ACCEPTED') {
        res.status(400).json(errorResponse('E2004', 'Cannot cancel an accepted invitation'));
        return;
      }

      await prisma.invitation.update({
        where: { id },
        data: {
          status: 'CANCELLED',
          cancelledAt: new Date(),
        }
      });

      res.json(successResponse({ message: 'Invitation cancelled successfully' }));
    } catch (error) {
      console.error('Cancel invitation error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // Accept invitation (public endpoint)
  async acceptInvitation(req: Request, res: Response): Promise<void> {
    try {
      const { token, password } = req.body;

      if (!token || !password) {
        res.status(400).json(errorResponse('E2001', 'Token and password are required'));
        return;
      }

      // Find invitation by token
      const invitation = await prisma.invitation.findUnique({
        where: { token },
        include: {
          invitedByTenant: true,
          tenant: true,
        }
      });

      if (!invitation) {
        res.status(404).json(errorResponse('E3001', 'Invitation not found or invalid token'));
        return;
      }

      if (invitation.status !== 'PENDING') {
        res.status(400).json(errorResponse('E2004', `Invitation is ${invitation.status.toLowerCase()}`));
        return;
      }

      if (invitation.expiresAt < new Date()) {
        await prisma.invitation.update({
          where: { id: invitation.id },
          data: { status: 'EXPIRED' }
        });
        res.status(400).json(errorResponse('E2004', 'Invitation has expired'));
        return;
      }

      // Determine tenant ID based on invitation type
      const targetTenantId = invitation.invitationType === 'TENANT_ADMIN'
        ? invitation.tenantId
        : invitation.invitedByTenantId;

      if (!targetTenantId) {
        res.status(400).json(errorResponse('E2004', 'Invalid invitation configuration'));
        return;
      }

      // Check if user already exists
      const existingUser = await prisma.user.findFirst({
        where: { tenantId: targetTenantId, mobile: invitation.mobile }
      });

      if (existingUser) {
        res.status(409).json(errorResponse('E3002', 'User with this mobile already exists'));
        return;
      }

      // Hash password
      const passwordHash = await bcrypt.hash(password, 10);

      // Create user
      const user = await prisma.user.create({
        data: {
          tenantId: targetTenantId,
          firstName: invitation.firstName,
          lastName: invitation.lastName,
          mobile: invitation.mobile,
          email: invitation.email,
          passwordHash,
          role: invitation.role,
          status: 'ACTIVE',
        }
      });

      // Update invitation
      await prisma.invitation.update({
        where: { id: invitation.id },
        data: {
          status: 'ACCEPTED',
          acceptedAt: new Date(),
          createdUserId: user.id,
        }
      });

      res.status(201).json(successResponse({
        message: 'Invitation accepted successfully',
        user: {
          id: user.id,
          firstName: user.firstName,
          lastName: user.lastName,
          mobile: user.mobile,
          email: user.email,
          role: user.role,
        }
      }));
    } catch (error) {
      console.error('Accept invitation error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // Validate invitation token (public endpoint)
  async validateToken(req: Request, res: Response): Promise<void> {
    try {
      const { token } = req.params;

      const invitation = await prisma.invitation.findUnique({
        where: { token },
        include: {
          invitedByTenant: {
            select: { name: true, slug: true, logoUrl: true }
          },
          tenant: {
            select: { name: true, slug: true, logoUrl: true }
          }
        }
      });

      if (!invitation) {
        res.status(404).json(errorResponse('E3001', 'Invalid invitation token'));
        return;
      }

      if (invitation.status !== 'PENDING') {
        res.status(400).json(errorResponse('E2004', `Invitation is ${invitation.status.toLowerCase()}`));
        return;
      }

      if (invitation.expiresAt < new Date()) {
        res.status(400).json(errorResponse('E2004', 'Invitation has expired'));
        return;
      }

      const tenant = invitation.invitationType === 'TENANT_ADMIN'
        ? invitation.tenant
        : invitation.invitedByTenant;

      res.json(successResponse({
        firstName: invitation.firstName,
        lastName: invitation.lastName,
        mobile: invitation.mobile,
        email: invitation.email,
        role: invitation.role,
        invitedByName: invitation.invitedByName,
        message: invitation.message,
        expiresAt: invitation.expiresAt,
        tenant,
      }));
    } catch (error) {
      console.error('Validate token error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }
}

import { Request, Response } from 'express';
import bcrypt from 'bcryptjs';
import { getTenantDb } from '../utils/tenantDb.js';
import {
  paginationSchema,
  successResponse,
  errorResponse,
  createPaginationMeta,
  calculateSkip,
} from '@electioncaffe/shared';

export class UserController {
  async getUsers(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const validation = paginationSchema.safeParse(req.query);

      if (!validation.success) {
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      const { page, limit, search, sort, order } = validation.data;
      const skip = calculateSkip(page, limit);

      const where: any = {};

      if (search) {
        where.OR = [
          { firstName: { contains: search, mode: 'insensitive' } },
          { lastName: { contains: search, mode: 'insensitive' } },
          { email: { contains: search, mode: 'insensitive' } },
          { mobile: { contains: search } },
        ];
      }

      const [users, total] = await Promise.all([
        tenantDb.user.findMany({
          where,
          skip,
          take: limit,
          orderBy: sort ? { [sort]: order } : { createdAt: 'desc' },
          select: {
            id: true,
            firstName: true,
            lastName: true,
            email: true,
            mobile: true,
            profilePhotoUrl: true,
            role: true,
            status: true,
            lastLoginAt: true,
            createdAt: true,
          },
        }),
        tenantDb.user.count({ where }),
      ]);

      res.json(successResponse(users, createPaginationMeta(total, page, limit)));
    } catch (error) {
      console.error('Get users error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async getUserById(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;

      const user = await tenantDb.user.findUnique({
        where: { id },
        select: {
          id: true,
          firstName: true,
          lastName: true,
          email: true,
          mobile: true,
          profilePhotoUrl: true,
          role: true,
          permissions: true,
          status: true,
          lastLoginAt: true,
          createdAt: true,
          updatedAt: true,
        },
      });

      if (!user) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      res.json(successResponse(user));
    } catch (error) {
      console.error('Get user by ID error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async createUser(req: Request, res: Response): Promise<void> {
    try {
      const tenantId = req.headers['x-tenant-id'] as string;
      const tenantDb = await getTenantDb(req);
      const { firstName, lastName, email, mobile, password, role } = req.body;

      // Check if user already exists
      const existingUser = await tenantDb.user.findFirst({
        where: { mobile },
      });

      if (existingUser) {
        res.status(409).json(errorResponse('E3002', 'User with this mobile already exists'));
        return;
      }

      const passwordHash = await bcrypt.hash(password || 'password123', 10);

      const user = await tenantDb.user.create({
        data: {
          tenantId,
          firstName,
          lastName,
          email,
          mobile,
          passwordHash,
          role: role || 'VOLUNTEER',
          status: 'ACTIVE',
        },
        select: {
          id: true,
          firstName: true,
          lastName: true,
          email: true,
          mobile: true,
          role: true,
          status: true,
          createdAt: true,
        },
      });

      res.status(201).json(successResponse(user));
    } catch (error) {
      console.error('Create user error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async updateUser(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;
      const { firstName, lastName, email, profilePhotoUrl, permissions } = req.body;

      const existingUser = await tenantDb.user.findUnique({
        where: { id },
      });

      if (!existingUser) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      const user = await tenantDb.user.update({
        where: { id },
        data: {
          ...(firstName && { firstName }),
          ...(lastName !== undefined && { lastName }),
          ...(email !== undefined && { email }),
          ...(profilePhotoUrl !== undefined && { profilePhotoUrl }),
          ...(permissions !== undefined && { permissions }),
        },
        select: {
          id: true,
          firstName: true,
          lastName: true,
          email: true,
          mobile: true,
          profilePhotoUrl: true,
          role: true,
          permissions: true,
          status: true,
          updatedAt: true,
        },
      });

      res.json(successResponse(user));
    } catch (error) {
      console.error('Update user error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async deleteUser(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const requestingUserId = req.headers['x-user-id'] as string;
      const { id } = req.params;

      if (id === requestingUserId) {
        res.status(400).json(errorResponse('E4004', 'Cannot delete your own account'));
        return;
      }

      const existingUser = await tenantDb.user.findUnique({
        where: { id },
      });

      if (!existingUser) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      await tenantDb.user.delete({ where: { id } });

      res.json(successResponse({ message: 'User deleted successfully' }));
    } catch (error) {
      console.error('Delete user error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async updateUserStatus(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const requestingUserId = req.headers['x-user-id'] as string;
      const { id } = req.params;
      const { status } = req.body;

      if (id === requestingUserId) {
        res.status(400).json(errorResponse('E4004', 'Cannot change your own status'));
        return;
      }

      if (!['ACTIVE', 'INACTIVE', 'BLOCKED'].includes(status)) {
        res.status(400).json(errorResponse('E2001', 'Invalid status'));
        return;
      }

      const existingUser = await tenantDb.user.findUnique({
        where: { id },
      });

      if (!existingUser) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      const user = await tenantDb.user.update({
        where: { id },
        data: { status },
        select: {
          id: true,
          firstName: true,
          lastName: true,
          status: true,
        },
      });

      // Invalidate refresh tokens if blocking user
      if (status === 'BLOCKED' || status === 'INACTIVE') {
        await tenantDb.refreshToken.deleteMany({ where: { userId: id } });
      }

      res.json(successResponse(user));
    } catch (error) {
      console.error('Update user status error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async updateUserRole(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const requestingUserId = req.headers['x-user-id'] as string;
      const requestingUserRole = req.headers['x-user-role'] as string;
      const { id } = req.params;
      const { role } = req.body;

      if (id === requestingUserId) {
        res.status(400).json(errorResponse('E4004', 'Cannot change your own role'));
        return;
      }

      const validRoles = ['TENANT_ADMIN', 'CAMPAIGN_MANAGER', 'COORDINATOR', 'BOOTH_INCHARGE', 'VOLUNTEER', 'AGENT'];
      if (!validRoles.includes(role)) {
        res.status(400).json(errorResponse('E2001', 'Invalid role'));
        return;
      }

      // Only tenant admin or super admin can assign admin roles
      if (role === 'TENANT_ADMIN' && !['SUPER_ADMIN', 'TENANT_ADMIN'].includes(requestingUserRole)) {
        res.status(403).json(errorResponse('E1005', 'Insufficient permissions to assign admin role'));
        return;
      }

      const existingUser = await tenantDb.user.findUnique({
        where: { id },
      });

      if (!existingUser) {
        res.status(404).json(errorResponse('E3001', 'User not found'));
        return;
      }

      const user = await tenantDb.user.update({
        where: { id },
        data: { role },
        select: {
          id: true,
          firstName: true,
          lastName: true,
          role: true,
        },
      });

      res.json(successResponse(user));
    } catch (error) {
      console.error('Update user role error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }
}

