      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async createBattleCard(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;
      const data = req.body;

      const candidate = await (tenantDb as any).candidate.findFirst({
        where: { id },
      });

      if (!candidate) {
        res.status(404).json(errorResponse('E3001', 'Candidate not found'));
        return;
      }

      if (!data.opponentId || !data.title) {
        res.status(400).json(errorResponse('E2001', 'Opponent ID and title are required'));
        return;
      }

      // Verify opponent exists
      const opponent = await (tenantDb as any).candidate.findFirst({
        where: { id: data.opponentId },
      });

      if (!opponent) {
        res.status(404).json(errorResponse('E3001', 'Opponent candidate not found'));
        return;
      }

      // Check if battle card already exists
      const existing = await (tenantDb as any).candidateBattleCard.findFirst({
        where: { candidateId: id, opponentId: data.opponentId },
      });

      if (existing) {
        res.status(400).json(errorResponse('E4001', 'Battle card for this opponent already exists'));
        return;
      }

      const battleCard = await (tenantDb as any).candidateBattleCard.create({
        data: {
          candidateId: id,
          opponentId: data.opponentId,
          title: data.title,
          summary: data.summary,
          ourStrengths: data.ourStrengths || [],
          opponentWeaknesses: data.opponentWeaknesses || [],
          keyIssues: data.keyIssues || [],
          talkingPoints: data.talkingPoints || [],
          counterArguments: data.counterArguments || [],
          voterAppeal: data.voterAppeal || {},
          headToHeadStats: data.headToHeadStats || {},
          createdBy: data.createdBy,
        },
        include: {
          opponent: {
            select: {
              id: true,
              name: true,
              photoUrl: true,
              party: {
                select: {
                  partyName: true,
                  partyShortName: true,
                  partyColor: true,
                },
              },
            },
          },
        },
      });

      res.status(201).json(successResponse(battleCard));
    } catch (error) {
      console.error('Create battle card error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async updateBattleCard(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id, bcId } = req.params;
      const data = req.body;

      const battleCard = await (tenantDb as any).candidateBattleCard.findFirst({
        where: { id: bcId, candidateId: id },
      });

      if (!battleCard) {
        res.status(404).json(errorResponse('E3001', 'Battle card not found'));
        return;
      }

      const updated = await (tenantDb as any).candidateBattleCard.update({
        where: { id: bcId },
        data: {
          ...(data.title && { title: data.title }),
          ...(data.summary !== undefined && { summary: data.summary }),
          ...(data.ourStrengths !== undefined && { ourStrengths: data.ourStrengths }),
          ...(data.opponentWeaknesses !== undefined && { opponentWeaknesses: data.opponentWeaknesses }),
          ...(data.keyIssues !== undefined && { keyIssues: data.keyIssues }),
          ...(data.talkingPoints !== undefined && { talkingPoints: data.talkingPoints }),
          ...(data.counterArguments !== undefined && { counterArguments: data.counterArguments }),
          ...(data.voterAppeal !== undefined && { voterAppeal: data.voterAppeal }),
          ...(data.headToHeadStats !== undefined && { headToHeadStats: data.headToHeadStats }),
          ...(data.isActive !== undefined && { isActive: data.isActive }),
        },
        include: {
          opponent: {
            select: {
              id: true,
              name: true,
              photoUrl: true,
              party: {
                select: {
                  partyName: true,
                  partyShortName: true,
                  partyColor: true,
                },
              },
            },
          },
        },
      });

      res.json(successResponse(updated));
    } catch (error) {
      console.error('Update battle card error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async deleteBattleCard(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id, bcId } = req.params;

      const battleCard = await (tenantDb as any).candidateBattleCard.findFirst({
        where: { id: bcId, candidateId: id },
      });

      if (!battleCard) {
        res.status(404).json(errorResponse('E3001', 'Battle card not found'));
        return;
      }

      await (tenantDb as any).candidateBattleCard.delete({ where: { id: bcId } });

      res.json(successResponse({ message: 'Battle card deleted successfully' }));
    } catch (error) {
      console.error('Delete battle card error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  // ==================== STATISTICS ====================

  async getCandidateStats(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;

      const candidate = await (tenantDb as any).candidate.findFirst({
        where: { id },
        include: {
          socialMedia: true,
          _count: {
            select: {
              documents: true,
              battleCards: true,
            },
          },
        },
      });

      if (!candidate) {
        res.status(404).json(errorResponse('E3001', 'Candidate not found'));
        return;
      }

      // Calculate total social media reach
      let totalFollowers = 0;
      let totalPosts = 0;
      const platformStats: any = {};

      for (const sm of candidate.socialMedia) {
        totalFollowers += sm.followers || 0;
        totalPosts += sm.posts || 0;
        platformStats[sm.platform] = {
          followers: sm.followers,
          posts: sm.posts,
          engagementRate: sm.engagementRate,
          verified: sm.verifiedStatus,
        };
      }

      const stats = {
        totalSocialMediaProfiles: candidate.socialMedia.length,
        totalFollowers,
        totalPosts,
        documentsCount: candidate._count.documents,
        battleCardsCount: candidate._count.battleCards,
        platformStats,
      };

      res.json(successResponse(stats));
    } catch (error) {
      console.error('Get candidate stats error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }
}

import { Request, Response } from 'express';
import { getTenantDb, coreDb } from '../utils/tenantDb.js';
import {
  createElectionSchema,
  updateElectionSchema,
  paginationSchema,
  successResponse,
  errorResponse,
  createPaginationMeta,
  calculateSkip,
} from '@electioncaffe/shared';

export class ElectionController {
  async getElections(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const validation = paginationSchema.safeParse(req.query);

      if (!validation.success) {
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      const { page, limit, search, sort, order } = validation.data;
      const skip = calculateSkip(page, limit);

      const where: any = {};

      if (search) {
        where.OR = [
          { name: { contains: search, mode: 'insensitive' } },
          { nameLocal: { contains: search, mode: 'insensitive' } },
          { constituency: { contains: search, mode: 'insensitive' } },
          { candidateName: { contains: search, mode: 'insensitive' } },
        ];
      }

      // Filter by status if provided
      if (req.query.status) {
        where.status = req.query.status;
      }

      const [elections, total] = await Promise.all([
        (tenantDb as any).election.findMany({
          where,
          skip,
          take: limit,
          orderBy: sort ? { [sort]: order } : { createdAt: 'desc' },
          include: {
            candidateParty: {
              select: {
                id: true,
                partyName: true,
                partyShortName: true,
                partyColor: true,
                partyImageUrl: true,
              },
            },
            _count: {
              select: {
                voters: true,
                parts: true,
                cadres: true,
              },
            },
          },
        }),
        (tenantDb as any).election.count({ where }),
      ]);

      res.json(successResponse(elections, createPaginationMeta(total, page, limit)));
    } catch (error) {
      console.error('Get elections error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async getElectionById(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;

      const election = await (tenantDb as any).election.findFirst({
        where: { id },
        include: {
          candidateParty: true,
          _count: {
            select: {
              voters: true,
              parts: true,
              sections: true,
              booths: true,
              cadres: true,
              families: true,
              religions: true,
              castes: true,
              languages: true,
              schemes: true,
              surveys: true,
            },
          },
        },
      });

      if (!election) {
        res.status(404).json(errorResponse('E3001', 'Election not found'));
        return;
      }

      res.json(successResponse(election));
    } catch (error) {
      console.error('Get election by ID error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async createElection(req: Request, res: Response): Promise<void> {
    try {
      const tenantId = req.headers['x-tenant-id'] as string;
      const tenantDb = await getTenantDb(req);
      const validation = createElectionSchema.safeParse(req.body);

      if (!validation.success) {
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      // Check tenant election limit from core database
      const tenant = await coreDb.tenant.findUnique({ where: { id: tenantId } });
      if (!tenant) {
        res.status(404).json(errorResponse('E3001', 'Tenant not found'));
        return;
      }

      const electionCount = await (tenantDb as any).election.count();
      if (electionCount >= tenant.maxElections) {
        res.status(400).json(errorResponse('E4003', `Maximum election limit (${tenant.maxElections}) reached`));
        return;
      }

      // Extract partyId if provided, handle properly
      const { partyId, ...electionData } = validation.data as any;

      const election = await (tenantDb as any).election.create({
        data: {
          ...electionData,
          tenantId,
          ...(partyId && { partyId }),
        },
      });

      // Create default master data for the election
      await this.createDefaultMasterData(tenantDb, election.id);

      res.status(201).json(successResponse(election));
    } catch (error) {
      console.error('Create election error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async updateElection(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;

      const existingElection = await (tenantDb as any).election.findFirst({
        where: { id },
      });

      if (!existingElection) {
        res.status(404).json(errorResponse('E3001', 'Election not found'));
        return;
      }

      if (existingElection.isLocked) {
        res.status(400).json(errorResponse('E4001', 'Election is locked and cannot be modified'));
        return;
      }

      const validation = updateElectionSchema.safeParse(req.body);

      if (!validation.success) {
        res.status(400).json(errorResponse('E2001', 'Validation error', validation.error.errors));
        return;
      }

      const election = await (tenantDb as any).election.update({
        where: { id },
        data: validation.data,
      });

      res.json(successResponse(election));
    } catch (error) {
      console.error('Update election error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async deleteElection(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;

      const existingElection = await (tenantDb as any).election.findFirst({
        where: { id },
      });

      if (!existingElection) {
        res.status(404).json(errorResponse('E3001', 'Election not found'));
        return;
      }

      if (existingElection.isLocked) {
        res.status(400).json(errorResponse('E4001', 'Election is locked and cannot be deleted'));
        return;
      }

      await (tenantDb as any).election.delete({ where: { id } });

      res.json(successResponse({ message: 'Election deleted successfully' }));
    } catch (error) {
      console.error('Delete election error:', error);
      res.status(500).json(errorResponse('E5001', 'Internal server error'));
    }
  }

  async lockElection(req: Request, res: Response): Promise<void> {
    try {
      const tenantDb = await getTenantDb(req);
      const { id } = req.params;

      const existingElection = await (tenantDb as any).election.findFirst({
        where: { id },
      });

      if (!existingElection) {
