                      <div className="preview-dot" />
                      <div className="preview-dot" />
                      <div className="preview-dot" />
                    </div>
                    <div className="preview-content">
                      <div className="preview-nav" />
                      <div className="preview-card" />
                      <div className="preview-card small" />
                    </div>
                  </div>
                </div>
