import { getPrisma } from '../../../lib/prisma';
import { ACTION_REGISTRY, isMessengerAction } from './registry';
import type { ActionContext, ActionResult } from './registry';

// ── Types ────────────────────────────────────────────────────

export interface DispatchResult {
  success: boolean;
  message: string;
  data?: unknown;
  refreshModules?: string[];
  requiresConfirmation?: boolean;
}

// ── Dispatch ─────────────────────────────────────────────────

export async function dispatchAction(
  actionName: string,
  rawArgs: Record<string, unknown>,
  ctx: ActionContext,
  confirmed: boolean,
): Promise<DispatchResult> {
  // 1. Messenger hard-block
  if (isMessengerAction(actionName)) {
    await logAudit(ctx, actionName, 'blocked:messenger', false);
    return { success: false, message: 'Messenger-Aktionen sind nicht verfuegbar.' };
  }

  // 2. Registry lookup
  const definition = ACTION_REGISTRY.get(actionName);
  if (!definition) {
    await logAudit(ctx, actionName, 'blocked:unknown_action', false);
    return { success: false, message: `Unbekannte Aktion: "${actionName}".` };
  }

  // 3. Role check
  if (definition.blockedRoles.has(ctx.role)) {
    await logAudit(ctx, actionName, `blocked:role=${ctx.role}`, false);
    return { success: false, message: 'Du hast keine Berechtigung fuer diese Aktion.' };
  }

  // 4. Zod validation
  const parseResult = definition.argsSchema.safeParse(rawArgs);
  if (!parseResult.success) {
    const errors = parseResult.error.issues.map((i) => i.message).join(', ');
    await logAudit(ctx, actionName, `blocked:validation (${errors})`, false);
    return { success: false, message: `Ungueltlge Eingabe: ${errors}` };
  }

  // 5. Destructive gate
  if (definition.category === 'destructive' && !confirmed) {
    return {
      success: false,
      message: 'Diese Aktion erfordert eine Bestaetigung.',
      requiresConfirmation: true,
    };
  }

  // 6. Execute handler
  try {
    const result = await definition.handler(parseResult.data as Record<string, unknown>, ctx);
    await logAudit(ctx, actionName, result.message, result.success);
    return result;
  } catch (error) {
    const msg = error instanceof Error ? error.message : 'Unbekannter Fehler';
    console.error(`[AI Agent] Action "${actionName}" failed:`, error);
    await logAudit(ctx, actionName, `error: ${msg}`, false);
    return { success: false, message: `Aktion fehlgeschlagen: ${msg}` };
  }
}

// ── Audit ────────────────────────────────────────────────────

async function logAudit(
  ctx: ActionContext,
  actionName: string,
  detail: string,
  success: boolean,
): Promise<void> {
  try {
    const prisma = getPrisma();
    await prisma.adminAuditEntry.create({
      data: {
        actorId: ctx.userId,
        actorName: ctx.actorName || ctx.userId,
        action: `ai:${actionName}`,
        target: success ? 'success' : 'failed',
        detail: detail.slice(0, 500),
        area: 'ai-assistant',
        userId: ctx.userId,
        teamId: ctx.teamId,
        clubId: ctx.clubId,
      },
    });
  } catch (err) {
    console.error('[AI Agent] Audit log failed:', err);
  }
}

