+
+    function buildOverview(company, sources) {
+      const bullets = [];
+
+      // Try to extract overview from markdown
+      if (company.markdown_content) {
+        const md = company.markdown_content;
+        // Look for overview/description section
+        const overviewMatch = md.match(/##?\s*(?:Company\s*)?Overview[^\n]*\n([\s\S]*?)(?=\n##|\n---|\n\*\*[A-Z]|$)/i)
+          || md.match(/##?\s*(?:Business\s*)?Description[^\n]*\n([\s\S]*?)(?=\n##|\n---|\n\*\*[A-Z]|$)/i);
+
+        if (overviewMatch) {
+          const lines = overviewMatch[1].split('\n')
+            .map(l => l.replace(/^[\s*-]+/, '').trim())
+            .filter(l => l.length > 10);
+          lines.forEach(l => bullets.push(l));
+        }
+      }
+
+      // Fallback: build from structured data
+      if (bullets.length === 0) {
+        if (company.founded_year) {
+          bullets.push(`Founded in ${company.founded_year}, ${company.name} is a ${(company.ownership_type || 'privately held').toLowerCase()} company based in ${company.location || company.province}.`);
+        } else {
+          bullets.push(`${company.name} is a ${(company.ownership_type || 'privately held').toLowerCase()} company based in ${company.location || company.province}.`);
+        }
+        if (company.industry) {
+          bullets.push(`Operates in the ${company.industry} sector${company.employee_count ? ` with approximately ${company.employee_count.toLocaleString()} employees` : ''}.`);
+        }
+        if (company.website) {
+          bullets.push(`Website: ${company.website}`);
+        }
+      }
+
+      // Add source footnotes for first few research sources
+      const overviewSources = sources.filter(s => s.source_type === 'company_website' || s.source_type === 'corporate_registry' || s.source_type === 'news');
+      overviewSources.slice(0, 3).forEach((s, i) => {
+        if (bullets[i] && s.source_url) {
+          bullets[i] += fn(s.source_url, s.source_name);
+        }
+      });
+
+      return `<ul>${bullets.map(b => `<li>${b}</li>`).join('')}</ul>`;
+    }
+
+    function renderProductsSection(company, sources) {
+      if (!company.markdown_content) return '';
+
+      const md = company.markdown_content;
+      const productsMatch = md.match(/##?\s*(?:Products?|Services?|Business\s*(?:Lines?|Units?|Segments?)|Operations?|Solutions?|Offerings?)[^\n]*\n([\s\S]*?)(?=\n##|\n---|\n\*\*(?:Key|Management|Board|M&A|Capital|Company News|Succession|Potential|Warm))/i);
+
+      if (!productsMatch) return '';
+
+      const lines = productsMatch[1].split('\n')
+        .map(l => l.replace(/^[\s*-]+/, '').trim())
+        .filter(l => l.length > 5);
+
+      if (lines.length === 0) return '';
+
+      // Add source footnotes
+      const productSources = sources.filter(s => s.source_type === 'company_website' || s.data_points?.some(dp => dp.toLowerCase().includes('product') || dp.toLowerCase().includes('service')));
+      lines.forEach((l, i) => {
+        if (productSources[0]?.source_url && i === 0) {
+          lines[i] += fn(productSources[0].source_url, productSources[0].source_name);
+        }
+      });
+
+      return `
+        <div class="section-bar">Products &amp; Services</div>
+        <div class="section-content">
+          <ul>${lines.map(l => `<li>${l}</li>`).join('')}</ul>
+        </div>
+      `;
+    }
+  </script>
+</body>
+</html>

