+        success: false,
+        action: 'get',
+        key: null,
+        error: 'The "key" parameter is required for the "get" action.',
+      };
+    }
+
+    if (!isAllowlisted(key)) {
+      return {
+        success: false,
+        action: 'get',
+        key,
+        error: `Setting "${key}" is not accessible. This setting can only be managed through the settings UI.`,
+      };
+    }
