+    // YOLO mode write guard (FR-003)
+    const isYolo = await this.checkYoloMode();
+    if (isYolo) {
+      return {
+        success: false,
+        action: 'set',
+        key,
+        error: 'Settings cannot be modified in YOLO mode. Please switch to balanced or high-speed mode first via the approval mode indicator.',
+      };
+    }
