+      settings.push({
+        key: entry.key,
+        category: entry.category,
+        label: entry.label,
+        description: entry.description,
+        currentValue,
+        type: entry.type,
+        allowedValues: entry.allowedValues,
+      });
+    }
+
+    return {
+      success: true,
+      action: 'list',
+      key: null,
