+// Get file contents from GitHub
+async function getGitHubFileContent(repo, filePath, branch = 'main') {
+  const cmd = `gh api repos/${repo}/contents/${filePath}?ref=${branch} --jq '.content' | base64 -d`;
+  return getGitHubData(cmd);
+}
