+    // Git operations
+    const gitAdd = execSync(`git add "${filepath}"`, { cwd: REPO_PATH, encoding: 'utf8' });
+    const gitCommit = execSync(`git commit -m "${commitMessage.replace(/"/g, '\\"')}"`, { cwd: REPO_PATH, encoding: 'utf8' });
