+  switch (intent.action) {
+    case 'list': {
+      const issues = await getJiraBacklog();
+      if (!issues || issues.length === 0) {
+        return "📋 **Backlog is empty!** No open issues found.";
+      }
+      const issueList = issues.slice(0, 15).map(i => {
