import * as crypto from "crypto";
import { getFirestore, FieldValue } from "firebase-admin/firestore";
import { C } from "./collections";
import type { McpApiKey, ApiKeyTier } from "./types";

const db = getFirestore();

/** Hash an API key using SHA-256 for secure storage. */
export function hashApiKey(rawKey: string): string {
  return crypto.createHash("sha256").update(rawKey).digest("hex");
}

/** Generate a new API key in the format ct_live_<32 random hex chars>. */
export function generateApiKey(): string {
  const randomPart = crypto.randomBytes(16).toString("hex");
  return `ct_live_${randomPart}`;
}

/** Get the current billing period string (YYYY-MM). */
function currentPeriod(): string {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
}

/**
 * Validate an API key and return the key document if valid.
 * Returns null if the key is invalid, revoked, or rate-limited.
 */
export async function validateApiKey(
  rawKey: string
): Promise<{ key: McpApiKey; error: null } | { key: null; error: string }> {
  const keyHash = hashApiKey(rawKey);

  // Look up by hash
  const snapshot = await db
    .collection(C.mcpApiKeys)
    .where("keyHash", "==", keyHash)
    .where("isActive", "==", true)
    .limit(1)
    .get();

  if (snapshot.empty) {
    return { key: null, error: "Invalid or revoked API key" };
  }

  const doc = snapshot.docs[0];
  const keyData = { id: doc.id, ...doc.data() } as McpApiKey;

  // Check if key is revoked
  if (keyData.revokedAt) {
    return { key: null, error: "API key has been revoked" };
  }

  // Reset monthly usage if we're in a new billing period
  const period = currentPeriod();
  if (keyData.usagePeriod !== period) {
    await doc.ref.update({
      usageThisMonth: 0,
      usagePeriod: period,
    });
    keyData.usageThisMonth = 0;
    keyData.usagePeriod = period;
  }

  // Check monthly rate limit
  if (keyData.usageThisMonth >= keyData.rateLimitPerMonth) {
    return { key: null, error: `Monthly rate limit exceeded (${keyData.rateLimitPerMonth} requests/month)` };
  }

  return { key: keyData, error: null };
}

/**
 * Record a usage event and increment the monthly counter.
 */
export async function recordUsage(
  keyId: string,
  tool: string,
  params: Record<string, unknown>,
  responseTimeMs: number
): Promise<void> {
  const keyRef = db.collection(C.mcpApiKeys).doc(keyId);

  // Increment counter + update lastUsedAt
  await keyRef.update({
    usageThisMonth: FieldValue.increment(1),
    lastUsedAt: FieldValue.serverTimestamp(),
  });

  // Write usage log
  await db.collection(C.mcpUsageLogs).add({
    keyId,
    tool,
    params,
    responseTimeMs,
    timestamp: FieldValue.serverTimestamp(),
  });
}

/**
 * Create a new API key. Returns the raw key (shown once) and the doc ID.
 */
export async function createApiKey(params: {
  ownerEmail: string;
  ownerName: string;
  tier: ApiKeyTier;
}): Promise<{ rawKey: string; docId: string }> {
  const rawKey = generateApiKey();
  const keyHash = hashApiKey(rawKey);
  const keyPrefix = rawKey.substring(0, 15) + "...";

  const { perMinute, perMonth } = await import("./types").then(m => m.TIER_LIMITS[params.tier]);

  const docRef = await db.collection(C.mcpApiKeys).add({
    keyHash,
    keyPrefix,
    ownerEmail: params.ownerEmail,
    ownerName: params.ownerName,
    tier: params.tier,
    isActive: true,
    rateLimitPerMinute: perMinute,
    rateLimitPerMonth: perMonth,
    usageThisMonth: 0,
    usagePeriod: `${new Date().getFullYear()}-${String(new Date().getMonth() + 1).padStart(2, "0")}`,
    createdAt: FieldValue.serverTimestamp(),
    updatedAt: FieldValue.serverTimestamp(),
  });

  return { rawKey, docId: docRef.id };
}

/**
 * Revoke an API key by doc ID.
 */
export async function revokeApiKey(docId: string): Promise<void> {
  await db.collection(C.mcpApiKeys).doc(docId).update({
    isActive: false,
    revokedAt: FieldValue.serverTimestamp(),
    updatedAt: FieldValue.serverTimestamp(),
  });
}

